module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);
parameter TIMEOUT = 60;
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
always @ (posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= idle;
        cnt <= 0;
        red <= 0;
        yellow <= 0;
        green <= 0;
    end else begin
        case (state)
            idle: begin
                cnt <= 0;
                red <= 0;
                yellow <= 0;
                green <= 0;
                state <= s1_red;
            end
            s1_red: begin
                red <= 1;
                yellow <= 0;
                green <= 0;
                if (cnt == 3) begin
                    state <= s2_yellow;
                    cnt <= 0;
                end else begin
                    cnt <= cnt + 1;
                end
            end
            s2_yellow: begin
                red <= 0;
                yellow <= 1;
                green <= 0;
                if (cnt == 3) begin
                    state <= s3_green;
                    cnt <= 0;
                end else begin
                    cnt <= cnt + 1;
                end
            end
            s3_green: begin
                red <= 0;
                yellow <= 0;
                green <= 1;
                if (cnt == 60) begin
                    state <= s2_yellow;
                    cnt <= 0;
                end else begin
                    cnt <= cnt + 1;
                end
            end
            default: begin
                state <= idle;
            end
        endcase
    end
end
always @ (posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        p_red <= 0;
        p_yellow <= 0;
        p_green <= 0;
    end else begin
        p_red <= red;
        p_yellow <= yellow;
        p_green <= green;
    end
end
assign clock = cnt;
endmodule
